def __init__(
    self,
    param_decls: cabc.Sequence[str] | None = None,
    show_default: bool | str | None = None,
    prompt: bool | str = False,
    confirmation_prompt: bool | str = False,
    prompt_required: bool = True,
    hide_input: bool = False,
    is_flag: bool | None = None,
    flag_value: t.Any | None = None,
    multiple: bool = False,
    count: bool = False,
    allow_from_autoenv: bool = True,
    type: types.ParamType | t.Any | None = None,
    help: str | None = None,
    hidden: bool = False,
    show_choices: bool = True,
    show_envvar: bool = False,
    deprecated: bool | str = False,
    **attrs: t.Any,
) -> None:
    if help:
        help = inspect.cleandoc(help)

    default_is_missing = "default" not in attrs
    super().__init__(
        param_decls, type=type, multiple=multiple, deprecated=deprecated, **attrs
    )

    if prompt is True:
        if self.name is None:
            raise TypeError("'name' is required with 'prompt=True'.")

        prompt_text: str | None = self.name.replace("_", " ").capitalize()
    elif prompt is False:
        prompt_text = None
    else:
        prompt_text = prompt

    if deprecated:
        deprecated_message = (
            f"(DEPRECATED: {deprecated})"
            if isinstance(deprecated, str)
            else "(DEPRECATED)"
        )
        help = help + deprecated_message if help is not None else deprecated_message

    self.prompt = prompt_text
    self.confirmation_prompt = confirmation_prompt
    self.prompt_required = prompt_required
    self.hide_input = hide_input
    self.hidden = hidden

    # If prompt is enabled but not required, then the option can be
    # used as a flag to indicate using prompt or flag_value.
    self._flag_needs_value = self.prompt is not None and not self.prompt_required

    if is_flag is None:
        if flag_value is not None:
            # Implicitly a flag because flag_value was set.
            is_flag = True
        elif self._flag_needs_value:
            # Not a flag, but when used as a flag it shows a prompt.
            is_flag = False
        else:
            # Implicitly a flag because flag options were given.
            is_flag = bool(self.secondary_opts)
    elif is_flag is False and not self._flag_needs_value:
        # Not a flag, and prompt is not enabled, can be used as a
        # flag if flag_value is set.
        self._flag_needs_value = flag_value is not None

    self.default: t.Any | t.Callable[[], t.Any]

    if is_flag and default_is_missing and not self.required:
        if multiple:
            self.default = ()
        else:
            self.default = False

    if is_flag and flag_value is None:
        flag_value = not self.default

    self.type: types.ParamType
    if is_flag and type is None:
        # Re-guess the type from the flag value instead of the
        # default.
        self.type = types.convert_type(None, flag_value)

    self.is_flag: bool = is_flag
    self.is_bool_flag: bool = is_flag and isinstance(self.type, types.BoolParamType)
    self.flag_value: t.Any = flag_value

    # Counting
    self.count = count
    if count:
        if type is None:
            self.type = types.IntRange(min=0)
        if default_is_missing:
            self.default = 0

    self.allow_from_autoenv = allow_from_autoenv
    self.help = help
    self.show_default = show_default
    self.show_choices = show_choices
    self.show_envvar = show_envvar

    if __debug__:
        if deprecated and prompt:
            raise ValueError("`deprecated` options cannot use `prompt`.")

        if self.nargs == -1:
            raise TypeError("nargs=-1 is not supported for options.")

        if self.prompt and self.is_flag and not self.is_bool_flag:
            raise TypeError("'prompt' is not valid for non-boolean flag.")

        if not self.is_bool_flag and self.secondary_opts:
            raise TypeError("Secondary flag is not valid for non-boolean flag.")

        if self.is_bool_flag and self.hide_input and self.prompt is not None:
            raise TypeError(
                "'prompt' with 'hide_input' is not valid for boolean flag."
            )

        if self.count:
            if self.multiple:
                raise TypeError("'count' is not valid with 'multiple'.")

            if self.is_flag:
                raise TypeError("'count' is not valid with 'is_flag'.")

def to_info_dict(self) -> dict[str, t.Any]:
    info_dict = super().to_info_dict()
    info_dict.update(
        help=self.help,
        prompt=self.prompt,
        is_flag=self.is_flag,
        flag_value=self.flag_value,
        count=self.count,
        hidden=self.hidden,
    )
    return info_dict

def get_error_hint(self, ctx: Context) -> str:
    result = super().get_error_hint(ctx)
    if self.show_envvar:
        result += f" (env var: '{self.envvar}')"
    return result

def _parse_decls(
    self, decls: cabc.Sequence[str], expose_value: bool
) -> tuple[str | None, list[str], list[str]]:
    opts = []
    secondary_opts = []
    name = None
    possible_names = []

    for decl in decls:
        if decl.isidentifier():
            if name is not None:
                raise TypeError(f"Name '{name}' defined twice")
            name = decl
        else:
            split_char = ";" if decl[:1] == "/" else "/"
            if split_char in decl:
                first, second = decl.split(split_char, 1)
                first = first.rstrip()
                if first:
                    possible_names.append(_split_opt(first))
                    opts.append(first)
                second = second.lstrip()
                if second:
                    secondary_opts.append(second.lstrip())
                if first == second:
                    raise ValueError(
                        f"Boolean option {decl!r} cannot use the"
                        " same flag for true/false."
                    )
            else:
                possible_names.append(_split_opt(decl))
                opts.append(decl)

    if name is None and possible_names:
        possible_names.sort(key=lambda x: -len(x[0]))  # group long options first
        name = possible_names[0][1].replace("-", "_").lower()
        if not name.isidentifier():
            name = None

    if name is None:
        if not expose_value:
            return None, opts, secondary_opts
        raise TypeError(
            f"Could not determine name for option with declarations {decls!r}"
        )

    if not opts and not secondary_opts:
        raise TypeError(
            f"No options defined but a name was passed ({name})."
            " Did you mean to declare an argument instead? Did"
            f" you mean to pass '--{name}'?"
        )

    return name, opts, secondary_opts

def add_to_parser(self, parser: _OptionParser, ctx: Context) -> None:
    if self.multiple:
        action = "append"
    elif self.count:
        action = "count"
    else:
        action = "store"

    if self.is_flag:
        action = f"{action}_const"

        if self.is_bool_flag and self.secondary_opts:
            parser.add_option(
                obj=self, opts=self.opts, dest=self.name, action=action, const=True
            )
            parser.add_option(
                obj=self,
                opts=self.secondary_opts,
                dest=self.name,
                action=action,
                const=False,
            )
        else:
            parser.add_option(
                obj=self,
                opts=self.opts,
                dest=self.name,
                action=action,
                const=self.flag_value,
            )
    else:
        parser.add_option(
            obj=self,
            opts=self.opts,
            dest=self.name,
            action=action,
            nargs=self.nargs,
        )

def get_help_record(self, ctx: Context) -> tuple[str, str] | None:
    if self.hidden:
        return None

    any_prefix_is_slash = False

    def _write_opts(opts: cabc.Sequence[str]) -> str:
        nonlocal any_prefix_is_slash

        rv, any_slashes = join_options(opts)

        if any_slashes:
            any_prefix_is_slash = True

        if not self.is_flag and not self.count:
            rv += f" {self.make_metavar(ctx=ctx)}"

        return rv

    rv = [_write_opts(self.opts)]

    if self.secondary_opts:
        rv.append(_write_opts(self.secondary_opts))

    help = self.help or ""

    extra = self.get_help_extra(ctx)
    extra_items = []
    if "envvars" in extra:
        extra_items.append(
            _("env var: {var}").format(var=", ".join(extra["envvars"]))
        )
    if "default" in extra:
        extra_items.append(_("default: {default}").format(default=extra["default"]))
    if "range" in extra:
        extra_items.append(extra["range"])
    if "required" in extra:
        extra_items.append(_(extra["required"]))

    if extra_items:
        extra_str = "; ".join(extra_items)
        help = f"{help}  [{extra_str}]" if help else f"[{extra_str}]"

    return ("; " if any_prefix_is_slash else " / ").join(rv), help

def get_help_extra(self, ctx: Context) -> types.OptionHelpExtra:
    extra: types.OptionHelpExtra = {}

    if self.show_envvar:
        envvar = self.envvar

        if envvar is None:
            if (
                self.allow_from_autoenv
                and ctx.auto_envvar_prefix is not None
                and self.name is not None
            ):
                envvar = f"{ctx.auto_envvar_prefix}_{self.name.upper()}"

        if envvar is not None:
            if isinstance(envvar, str):
                extra["envvars"] = (envvar,)
            else:
                extra["envvars"] = tuple(str(d) for d in envvar)

    # Temporarily enable resilient parsing to avoid type casting
    # failing for the default. Might be possible to extend this to
    # help formatting in general.
    resilient = ctx.resilient_parsing
    ctx.resilient_parsing = True

    try:
        default_value = self.get_default(ctx, call=False)
    finally:
        ctx.resilient_parsing = resilient

    show_default = False
    show_default_is_str = False

    if self.show_default is not None:
        if isinstance(self.show_default, str):
            show_default_is_str = show_default = True
        else:
            show_default = self.show_default
    elif ctx.show_default is not None:
        show_default = ctx.show_default

    if show_default_is_str or (show_default and (default_value is not None)):
        if show_default_is_str:
            default_string = f"({self.show_default})"
        elif isinstance(default_value, (list, tuple)):
            default_string = ", ".join(str(d) for d in default_value)
        elif inspect.isfunction(default_value):
            default_string = _("(dynamic)")
        elif self.is_bool_flag and self.secondary_opts:
            # For boolean flags that have distinct True/False opts,
            # use the opt without prefix instead of the value.
            default_string = _split_opt(
                (self.opts if default_value else self.secondary_opts)[0]
            )[1]
        elif self.is_bool_flag and not self.secondary_opts and not default_value:
            default_string = ""
        elif default_value == "":
            default_string = '""'
        else:
            default_string = str(default_value)

        if default_string:
            extra["default"] = default_string

    if (
        isinstance(self.type, types._NumberRangeBase)
        # skip count with default range type
        and not (self.count and self.type.min == 0 and self.type.max is None)
    ):
        range_str = self.type._describe_range()

        if range_str:
            extra["range"] = range_str

    if self.required:
        extra["required"] = "required"

    return extra

@t.overload
def get_default(
    self, ctx: Context, call: t.Literal[True] = True
) -> t.Any | None: ...

@t.overload

def get_default(
    self, ctx: Context, call: t.Literal[True] = True
) -> t.Any | None: ...

@t.overload
def get_default(
    self, ctx: Context, call: bool = ...
) -> t.Any | t.Callable[[], t.Any] | None: ...

def get_default(
    self, ctx: Context, call: bool = True
) -> t.Any | t.Callable[[], t.Any] | None:
    """Get the default for the parameter. Tries
    :meth:`Context.lookup_default` first, then the local default.

    :param ctx: Current context.
    :param call: If the default is a callable, call it. Disable to
        return the callable instead.

    .. versionchanged:: 8.0.2
        Type casting is no longer performed when getting a default.

    .. versionchanged:: 8.0.1
        Type casting can fail in resilient parsing mode. Invalid
        defaults will not prevent showing help text.

    .. versionchanged:: 8.0
        Looks at ``ctx.default_map`` first.

    .. versionchanged:: 8.0
        Added the ``call`` parameter.
    """
    value = ctx.lookup_default(self.name, call=False)  # type: ignore

    if value is None:
        value = self.default

    if call and callable(value):
        value = value()

    return value

def add_to_parser(self, parser: _OptionParser, ctx: Context) -> None:
    raise NotImplementedError()

def consume_value(
    self, ctx: Context, opts: cabc.Mapping[str, t.Any]
) -> tuple[t.Any, ParameterSource]:
    value = opts.get(self.name)  # type: ignore
    source = ParameterSource.COMMANDLINE

    if value is None:
        value = self.value_from_envvar(ctx)
        source = ParameterSource.ENVIRONMENT

    if value is None:
        value = ctx.lookup_default(self.name)  # type: ignore
        source = ParameterSource.DEFAULT_MAP

    if value is None:
        value = self.get_default(ctx)
        source = ParameterSource.DEFAULT

    return value, source

def type_cast_value(self, ctx: Context, value: t.Any) -> t.Any:
    """Convert and validate a value against the option's
    :attr:`type`, :attr:`multiple`, and :attr:`nargs`.
    """
    if value is None:
        return () if self.multiple or self.nargs == -1 else None

    def check_iter(value: t.Any) -> cabc.Iterator[t.Any]:
        try:
            return _check_iter(value)
        except TypeError:
            # This should only happen when passing in args manually,
            # the parser should construct an iterable when parsing
            # the command line.
            raise BadParameter(
                _("Value must be an iterable."), ctx=ctx, param=self
            ) from None

    if self.nargs == 1 or self.type.is_composite:

        def convert(value: t.Any) -> t.Any:
            return self.type(value, param=self, ctx=ctx)

    elif self.nargs == -1:

        def convert(value: t.Any) -> t.Any:  # tuple[t.Any, ...]
            return tuple(self.type(x, self, ctx) for x in check_iter(value))

    else:  # nargs > 1

        def convert(value: t.Any) -> t.Any:  # tuple[t.Any, ...]
            value = tuple(check_iter(value))

            if len(value) != self.nargs:
                raise BadParameter(
                    ngettext(
                        "Takes {nargs} values but 1 was given.",
                        "Takes {nargs} values but {len} were given.",
                        len(value),
                    ).format(nargs=self.nargs, len=len(value)),
                    ctx=ctx,
                    param=self,
                )

            return tuple(self.type(x, self, ctx) for x in value)

    if self.multiple:
        return tuple(convert(x) for x in check_iter(value))

    return convert(value)

def value_is_missing(self, value: t.Any) -> bool:
    if value is None:
        return True

    if (self.nargs != 1 or self.multiple) and value == ():
        return True

    return False

def process_value(self, ctx: Context, value: t.Any) -> t.Any:
    value = self.type_cast_value(ctx, value)

    if self.required and self.value_is_missing(value):
        raise MissingParameter(ctx=ctx, param=self)

def __init__(
    self,
    param_decls: cabc.Sequence[str] | None = None,
    type: types.ParamType | t.Any | None = None,
    required: bool = False,
    default: t.Any | t.Callable[[], t.Any] | None = None,
    callback: t.Callable[[Context, Parameter, t.Any], t.Any] | None = None,
    nargs: int | None = None,
    multiple: bool = False,
    metavar: str | None = None,
    expose_value: bool = True,
    is_eager: bool = False,
    envvar: str | cabc.Sequence[str] | None = None,
    shell_complete: t.Callable[
        [Context, Parameter, str], list[CompletionItem] | list[str]
    ]
    | None = None,
    deprecated: bool | str = False,
) -> None:
    self.name: str | None
    self.opts: list[str]
    self.secondary_opts: list[str]
    self.name, self.opts, self.secondary_opts = self._parse_decls(
        param_decls or (), expose_value
    )
    self.type: types.ParamType = types.convert_type(type, default)

    # Default nargs to what the type tells us if we have that
    # information available.
    if nargs is None:
        if self.type.is_composite:
            nargs = self.type.arity
        else:
            nargs = 1

    self.required = required
    self.callback = callback
    self.nargs = nargs
    self.multiple = multiple
    self.expose_value = expose_value
    self.default = default
    self.is_eager = is_eager
    self.metavar = metavar
    self.envvar = envvar
    self._custom_shell_complete = shell_complete
    self.deprecated = deprecated

    if __debug__:
        if self.type.is_composite and nargs != self.type.arity:
            raise ValueError(
                f"'nargs' must be {self.type.arity} (or None) for"
                f" type {self.type!r}, but it was {nargs}."
            )

        # Skip no default or callable default.
        check_default = default if not callable(default) else None

        if check_default is not None:
            if multiple:
                try:
                    # Only check the first value against nargs.
                    check_default = next(_check_iter(check_default), None)
                except TypeError:
                    raise ValueError(
                        "'default' must be a list when 'multiple' is true."
                    ) from None

            # Can be None for multiple with empty default.
            if nargs != 1 and check_default is not None:
                try:
                    _check_iter(check_default)
                except TypeError:
                    if multiple:
                        message = (
                            "'default' must be a list of lists when 'multiple' is"
                            " true and 'nargs' != 1."
                        )
                    else:
                        message = "'default' must be a list when 'nargs' != 1."

                    raise ValueError(message) from None

                if nargs > 1 and len(check_default) != nargs:
                    subject = "item length" if multiple else "length"
                    raise ValueError(
                        f"'default' {subject} must match nargs={nargs}."
                    )

        if required and deprecated:
            raise ValueError(
                f"The {self.param_type_name} '{self.human_readable_name}' "
                "is deprecated and still required. A deprecated "
                f"{self.param_type_name} cannot be required."
            )

def to_info_dict(self) -> dict[str, t.Any]:
    """Gather information that could be useful for a tool generating
    user-facing documentation.

    Use :meth:`click.Context.to_info_dict` to traverse the entire
    CLI structure.

    .. versionadded:: 8.0
    """
    return {
        "name": self.name,
        "param_type_name": self.param_type_name,
        "opts": self.opts,
        "secondary_opts": self.secondary_opts,
        "type": self.type.to_info_dict(),
        "required": self.required,
        "nargs": self.nargs,
        "multiple": self.multiple,
        "default": self.default,
        "envvar": self.envvar,
    }

def __repr__(self) -> str:
    return f"<{self.__class__.__name__} {self.name}>"

def _parse_decls(
    self, decls: cabc.Sequence[str], expose_value: bool
) -> tuple[str | None, list[str], list[str]]:
    raise NotImplementedError()

@property
def human_readable_name(self) -> str:
    """Returns the human readable name of this parameter.  This is the
